/**
 * Build the room actor from CLI flags. callsign comes from --as (or --engine); cli/engine from --engine.
 */
// @kern-source: room:13
export function actorFromArgs(args: any): RoomActor {
  const engine = (args.engine as string | undefined) || undefined;
  const callsign = String((args.as as string) || engine || 'me').toLowerCase();
  const cli = engine || 'cli';
  const humanOwner = process.env.USER || process.env.USERNAME || 'local';
  return {
    actorId: `${cli}:${callsign}`,
    callsign,
    kind: 'external-cli',
    engineId: engine,
    cli,
    humanOwner,
  };
}

/**
 * One transcript line. Posts show the body; join/leave/close render as system lines.
 */
// @kern-source: room:30
export function renderEvent(ev: RoomEvent): string {
  const t = new Date(ev.createdAt);
  const hh = String(t.getHours()).padStart(2, '0');
  const mm = String(t.getMinutes()).padStart(2, '0');
  const stamp = dim(`${hh}:${mm}`);
  const seq = dim(`#${ev.seq}`);
  const who = bold(green(ev.actor.callsign));
  if (ev.kind === 'post') {
    return `${seq} ${stamp} ${who}: ${ev.body}`;
  }
  if (ev.kind === 'join') return `${seq} ${stamp} ${dim('* ' + ev.actor.callsign + ' joined')}`;
  if (ev.kind === 'leave' || ev.kind === 'room-closed') return `${seq} ${stamp} ${dim('* ' + ev.actor.callsign + ' left')}`;
  return `${seq} ${stamp} ${dim('* ' + ev.kind + ' by ' + ev.actor.callsign)}`;
}

